import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import API from "../api";

const Register = () => {
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await API.post("/auth/signup", form);
      localStorage.setItem("token", res.data.token);
      localStorage.setItem("user", JSON.stringify(res.data.user));
      if (res.data.user.role === "admin") navigate("/admin");
      else navigate("/home");
    } catch (err) {
      setError(err.response?.data?.message || "Registration failed");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-600 via-purple-600 to-pink-500">
      <div className="bg-white p-10 rounded-2xl shadow-2xl w-full max-w-md">
        <h2 className="text-3xl font-bold text-center mb-6">Register</h2>
        {error && <p className="text-red-600 mb-2">{error}</p>}
        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          <input type="text" name="name" placeholder="Full Name" className="border p-2 rounded" value={form.name} onChange={handleChange} required />
          <input type="email" name="email" placeholder="Email" className="border p-2 rounded" value={form.email} onChange={handleChange} required />
          <input type="password" name="password" placeholder="Password" className="border p-2 rounded" value={form.password} onChange={handleChange} required />
          <button type="submit" className="bg-purple-600 text-white p-2 rounded mt-2">Register</button>
        </form>
        <p className="mt-4 text-sm">Already have an account? <Link to="/login" className="text-purple-600 font-semibold">Login</Link></p>
      </div>
    </div>
  );
};

export default Register;
